def solve(emails):
    unique_emails = set()
    for email in emails:
        local, domain = email.split('@')
        if '+' in local:
            local = local[:local.index('+')]
        unique_emails.add(local.replace('.', '') + '@' + domain)
    return len(unique_emails)

